const rows = $input.first().json;
const t = Array.isArray(rows) ? rows[0] : rows;
if (!t) throw new Error("Ticket no encontrado");

const bucket = "empresas"; // si tu bucket se llama así
const prefix = bucket + "/";
const objectPath = t.csv_key?.startsWith(prefix) ? t.csv_key.slice(prefix.length) : t.csv_key;

if (!objectPath) throw new Error("Ticket sin csv_key");

return [{
  json: {
    ticket: t,
    bucket,
    objectPath
  }
}];

const rows = $input.first().json;
const r = Array.isArray(rows) ? rows[0] : rows;

if (!r?.signedURL) throw new Error("No viene signedURL");

const base = "https://oyktngpmaevmahrtmguw.supabase.co/storage/v1";
const full = base + r.signedURL; // r.signedURL empieza por /object/sign/...

return [{ json: { signedUrlFull: full } }];

const signedURL = $json.signedURL;

if (!signedURL) {
  throw new Error("No viene signedURL en la respuesta de Supabase");
}

// Cambia este dominio por el tuyo real de Supabase
const SUPABASE_URL = "https://oyktngpmaevmahrtmguw.supabase.co";

return [
  {
    pdfUrl: `${SUPABASE_URL}/storage/v1${signedURL}`,
  },
];

// Corrige BOM en el nombre de campo "firstname"
function formatearNombre(s) {
  if (!s) return "";
  return String(s)
    .replace(/^\uFEFF/, "")      // quitar BOM
    .trim()
    .replace(/\s+/g, " ")
    .toLowerCase()
    .split(" ")
    .map(p => p ? p[0].toUpperCase() + p.slice(1) : "")
    .join(" ");
}

const firstnameRaw = $json["﻿firstname"] ?? $json.firstname ?? "";
const lastnameRaw  = $json.lastname ?? "";

return {
  ...$json,
  firstname: formatearNombre(firstnameRaw),
  lastname: formatearNombre(lastnameRaw),
  nombre_completo: `${formatearNombre(firstnameRaw)} ${formatearNombre(lastnameRaw)}`.trim()
};

const t = $items("Normalizar ticket + preparar storage path")[0].json.ticket;

return {
  ticket_id: t.id,
};

if (item.binary?.pdf?.fileName) {
  let decoded = decodeURIComponent(item.binary.pdf.fileName);

  const corrections = {
    "COMO": "CÓMO",
    "MAS": "MÁS",
    "ANIOS": "AÑOS"
  };

  for (const [wrong, correct] of Object.entries(corrections)) {
    const regex = new RegExp(`\\b${wrong}\\b`, "g");
    decoded = decoded.replace(regex, correct);
  }

  item.binary.pdf.fileName = decoded;
}

return item;

